#include <bits/stdc++.h>
using namespace std;
const int N=505;
int n,m,c,x,y,flag[2][N][N],f[2][N*N],ans[2];
int fa(int c,int x)
{
    if(f[c][x]==x) return x;
    return f[c][x]=fa(c,f[c][x]);
}
void merge(int c,int x,int y)
{
    int fx=fa(c,x),fy=fa(c,y);
    if(fx==fy) return ;
    f[c][fx]=fy;
    ans[c]--;
}
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n*n;i++)
    {
        f[0][i]=f[1][i]=i;
    }
    for(int i=1;i<=m;i++)
    {
        cin>>c>>x>>y;
        flag[c][x][y]=1;
        ans[c]++;
		if(y>1&&flag[c][x][y-1]) merge(c,(x-1)*n+y,(x-1)*n+y-1);
        if(y<n&&flag[c][x][y+1]) merge(c,(x-1)*n+y,(x-1)*n+y+1);
		if(x>1&&flag[c][x-1][y]) merge(c,(x-1)*n+y,(x-2)*n+y);
		if(x<n&&flag[c][x+1][y]) merge(c,(x-1)*n+y,x*n+y);
        cout<<ans[0]+ans[1]<<'\n';
    }
    return 0;
}
